225→    public void maybeWaitForNonEmptyTopology(final Supplier<StreamThread.State> threadState) {
226→        if (isEmpty() && threadState.get().isAlive()) {
227→            try {
228→                lock();
229→                while (isEmpty() && threadState.get().isAlive()) {
230→                    try {
231→                        log.debug("Detected that the topology is currently empty, waiting for something to process");
232→                        version.topologyCV.await();
233→                    } catch (final InterruptedException e) {
234→                        log.error("StreamThread was interrupted while waiting on empty topology", e);
235→                    }
236→                }
237→            } finally {
238→                unlock();
239→            }
240→        }
241→    }
