247→        try {
248→            lock();
249→            buildAndVerifyTopology(newTopologyBuilder);
250→            log.info("New NamedTopology {} passed validation and will be added, old topology version is {}", newTopologyBuilder.topologyName(), version.topologyVersion.get());
251→            version.topologyVersion.incrementAndGet();
252→            version.activeTopologyUpdateListeners.add(new TopologyVersionListener(topologyVersion(), future));
253→            builders.put(newTopologyBuilder.topologyName(), newTopologyBuilder);
254→            wakeupThreads();
255→            log.info("Added NamedTopology {} and updated topology version to {}", newTopologyBuilder.topologyName(), version.topologyVersion.get());
256→        } catch (final Throwable throwable) {
257→            log.error("Failed to add NamedTopology {}, please retry the operation.", newTopologyBuilder.topologyName());
258→            future.completeExceptionally(throwable);
259→        } finally {
260→            unlock();
261→        }
262→    }
