293→                                                final String topologyName) {
294→        try {
295→            lock();
296→            log.info("Beginning removal of NamedTopology {}, old topology version is {}", topologyName, version.topologyVersion.get());
297→            version.topologyVersion.incrementAndGet();
298→            version.activeTopologyUpdateListeners.add(new TopologyVersionListener(topologyVersion(), removeTopologyFuture));
299→            final InternalTopologyBuilder removedBuilder = builders.remove(topologyName);
300→            removedBuilder.fullSourceTopicNames().forEach(allInputTopics::remove);
301→            removedBuilder.allSourcePatternStrings().forEach(allInputTopics::remove);
302→            log.info("Finished removing NamedTopology {}, topology version was updated to {}", topologyName, version.topologyVersion.get());
303→        } catch (final Throwable throwable) {
304→            log.error("Failed to remove NamedTopology {}, please retry.", topologyName);
305→            removeTopologyFuture.completeExceptionally(throwable);
306→        } finally {
307→            unlock();
308→        }
309→        return removeTopologyFuture;
310→    }
