658→    public static class Subtopology implements Comparable<Subtopology> {
659→        final int nodeGroupId;
660→        final String namedTopology;
661→
662→        public Subtopology(final int nodeGroupId, final String namedTopology) {
663→            this.nodeGroupId = nodeGroupId;
664→            this.namedTopology = namedTopology;
665→        }
666→
667→        @Override
668→        public boolean equals(final Object o) {
669→            if (this == o) {
670→                return true;
671→            }
672→            if (o == null || getClass() != o.getClass()) {
673→                return false;
674→            }
675→            final Subtopology that = (Subtopology) o;
676→            return nodeGroupId == that.nodeGroupId &&
677→                    Objects.equals(namedTopology, that.namedTopology);
678→        }
679→
680→        @Override
681→        public int hashCode() {
682→            return Objects.hash(nodeGroupId, namedTopology);
683→        }
684→
685→        @Override
686→        public int compareTo(final Subtopology other) {
687→            if (nodeGroupId != other.nodeGroupId) {
688→                return Integer.compare(nodeGroupId, other.nodeGroupId);
689→            }
690→            if (namedTopology == null) {
691→                return other.namedTopology == null ? 0 : -1;
692→            }
693→            if (other.namedTopology == null) {
694→                return 1;
695→            }
696→
697→            // Both not null
698→            return namedTopology.compareTo(other.namedTopology);
699→        }
700→    }
