 19→import org.slf4j.Logger;
 20→import org.slf4j.LoggerFactory;
 21→
 22→import java.util.List;
 23→import java.util.concurrent.CopyOnWriteArrayList;
 24→import java.util.concurrent.ThreadLocalRandom;
 25→import java.util.concurrent.locks.Condition;
 26→import java.util.concurrent.locks.ReentrantLock;
 27→
 28→/**
 29→ * Manages authenticated sessions for the metrics transport layer.
 30→ * Sessions have an expiry time and a shard assignment; during rebalancing
 31→ * the shard may change, which triggers listener notifications.
 32→ */
 33→public class MetricsSessionManager {
 34→
 35→    private static final Logger log = LoggerFactory.getLogger(MetricsSessionManager.class);
 36→
 37→    private final ReentrantLock sessionLock = new ReentrantLock();
 38→    private final Condition sessionReady = sessionLock.newCondition();
 39→    private final long sessionTtlMs;
 40→
 41→    private volatile MetricsSession currentSession;
 42→    private boolean rebalancingMode = false;
 43→
 44→    private final List<MetricsSessionListener> listeners = new CopyOnWriteArrayList<>();
 45→
 46→    public MetricsSessionManager(final long sessionTtlMs) {
 47→        this.sessionTtlMs = sessionTtlMs;
 48→        this.currentSession = new MetricsSession(
 49→            "init-" + ThreadLocalRandom.current().nextInt(10000),
 50→            0,
 51→            System.currentTimeMillis() + sessionTtlMs
 52→        );
 53→    }
 54→
 55→    public void registerListener(final MetricsSessionListener listener) {
 56→        listeners.add(listener);
 57→    }
 58→
 59→    public void setRebalancingMode(final boolean rebalancing) {
 60→        sessionLock.lock();
 61→        try {
 62→            this.rebalancingMode = rebalancing;
 63→            log.debug("Metrics session manager rebalancing mode set to {}", rebalancing);
 64→        } finally {
 65→            sessionLock.unlock();
 66→        }
 67→    }
 68→
 69→    /**
 70→     * Returns the current session. The returned reference is safe to read
 71→     * without holding the lock due to the volatile field, but the session
 72→     * may expire at any time.
 73→     */
 74→    public MetricsSession currentSession() {
 75→        return currentSession;
 76→    }
 77→
 78→    /**
 79→     * If the current session has expired, renew it.
 80→     */
 81→    public void refreshSessionIfExpired() {
 82→        sessionLock.lock();
 83→        try {
 84→            if (currentSession != null && currentSession.expiryMs > System.currentTimeMillis()) {
 85→                return; // still valid
 86→            }
 87→            renewSessionInternal();
 88→        } finally {
 89→            sessionLock.unlock();
 90→        }
 91→    }
 92→
 93→    /**
 94→     * Force a session renewal regardless of expiry status.
 95→     */
 96→    public void renewSession() {
 97→        sessionLock.lock();
 98→        try {
 99→            renewSessionInternal();
100→        } finally {
101→            sessionLock.unlock();
102→        }
103→    }
104→
105→    private void renewSessionInternal() {
106→        final MetricsSession oldSession = currentSession;
107→        final int newShardId;
108→        if (rebalancingMode) {
109→            // During rebalancing, the shard assignment may change
110→            newShardId = ThreadLocalRandom.current().nextInt(1024);
111→        } else {
112→            newShardId = oldSession != null ? oldSession.shardId : 0;
113→        }
114→
115→        final MetricsSession newSession = new MetricsSession(
116→            "sess-" + ThreadLocalRandom.current().nextInt(100000),
117→            newShardId,
118→            System.currentTimeMillis() + sessionTtlMs
119→        );
120→        currentSession = newSession;
121→        log.debug("Renewed metrics session: old={}, new={}", oldSession, newSession);
122→
123→        notifyListeners(oldSession, newSession);
124→        sessionReady.signalAll();
125→    }
126→
127→    private void notifyListeners(final MetricsSession oldSession, final MetricsSession newSession) {
128→        for (final MetricsSessionListener listener : listeners) {
129→            try {
130→                listener.onSessionChanged(oldSession, newSession);
131→            } catch (final Exception e) {
132→                log.warn("Metrics session listener threw exception", e);
133→            }
134→        }
135→    }
136→
137→    /**
138→     * Represents an authenticated metrics session with a token, shard
139→     * assignment, and expiry timestamp.
140→     */
141→    public static class MetricsSession {
142→        public final String token;
143→        public final int shardId;
144→        public final long expiryMs;
145→
146→        public MetricsSession(final String token, final int shardId, final long expiryMs) {
147→            this.token = token;
148→            this.shardId = shardId;
149→            this.expiryMs = expiryMs;
150→        }
151→
152→        @Override
153→        public String toString() {
154→            return "MetricsSession{token='" + token + "', shard=" + shardId + ", expiry=" + expiryMs + "}";
155→        }
156→    }
157→}
