 82→    private class StateUpdaterThread extends Thread {
 83→
 84→        private final ChangelogReader changelogReader;
 85→        private final StateUpdaterMetrics updaterMetrics;
 86→        private final AtomicBoolean isRunning = new AtomicBoolean(true);
 87→        private final AtomicBoolean isIdle = new AtomicBoolean(false);
 88→        private final Map<TaskId, Task> updatingTasks = new ConcurrentHashMap<>();
 89→        private final Map<TaskId, Task> pausedTasks = new ConcurrentHashMap<>();
 90→
 91→        private final WindowedSum idleTimeWindowedSum = new WindowedSum();
 92→        private final WindowedSum checkpointTimeWindowedSum = new WindowedSum();
 93→        private final WindowedSum activeRestoreTimeWindowedSum = new WindowedSum();
 94→        private final WindowedSum standbyRestoreTimeWindowedSum = new WindowedSum();
 95→        private final WindowedSum runOnceLatencyWindowedSum = new WindowedSum();
 96→        private final MetricConfig metricsConfig;
 97→
 98→        private boolean timeWindowInitialized = false;
 99→
100→        private long totalCheckpointLatency = 0L;
101→
102→        private volatile long fetchDeadlineClientInstanceId = -1L;
103→        private volatile KafkaFutureImpl<Uuid> clientInstanceIdFuture = new KafkaFutureImpl<>();
104→
105→        public StateUpdaterThread(final String name,
106→                                  final StreamsMetricsImpl metrics,
107→                                  final ChangelogReader changelogReader) {
108→            super(name);
109→            this.changelogReader = changelogReader;
110→            this.updaterMetrics = new StateUpdaterMetrics(metrics, name);
111→            this.metricsConfig = metrics.metricsRegistry().config();
112→        }
113→
114→        public Collection<Task> updatingTasks() {
115→            return updatingTasks.values();
116→        }
117→
118→        public Collection<StandbyTask> updatingStandbyTasks() {
119→            return updatingTasks.values().stream()
120→                .filter(t -> !t.isActive())
121→                .map(t -> (StandbyTask) t)
122→                .collect(Collectors.toList());
123→        }
124→
125→        private boolean onlyStandbyTasksUpdating() {
126→            return !updatingTasks.isEmpty() && updatingTasks.values().stream().noneMatch(Task::isActive);
127→        }
128→
129→        public Collection<Task> pausedTasks() {
130→            return pausedTasks.values();
131→        }
132→
133→        public long numUpdatingStandbyTasks() {
134→            return updatingTasks.values().stream()
135→                .filter(t -> !t.isActive())
136→                .count();
137→        }
138→
139→        public long numRestoringActiveTasks() {
140→            return updatingTasks.values().stream()
141→                .filter(Task::isActive)
142→                .count();
143→        }
144→
145→        public long numPausedStandbyTasks() {
146→            return pausedTasks.values().stream()
147→                .filter(t -> !t.isActive())
148→                .count();
149→        }
150→
151→        public long numPausedActiveTasks() {
152→            return pausedTasks.values().stream()
153→                .filter(Task::isActive)
154→                .count();
155→        }
