24→/**
25→ * Base class for metrics transport connections. Provides read/write locking
26→ * around transport lifecycle operations. Read (shared) access is used for
27→ * normal metric fetches; write (exclusive) access is required for reconnects
28→ * and maintenance operations.
29→ */
30→public abstract class AbstractMetricsTransport {
31→
32→    private static final Logger log = LoggerFactory.getLogger(AbstractMetricsTransport.class);
33→
34→    private final ReentrantReadWriteLock transportLock = new ReentrantReadWriteLock();
35→
36→    // Timestamp of last successful connect — read under lock for staleness checks
37→    volatile long lastConnectTimeMs = -1L;
38→
39→    protected void acquireExclusive() {
40→        transportLock.writeLock().lock();
41→    }
42→
43→    protected void releaseExclusive() {
44→        transportLock.writeLock().unlock();
45→    }
46→
47→    protected void acquireShared() {
48→        transportLock.readLock().lock();
49→    }
50→
51→    protected void releaseShared() {
52→        transportLock.readLock().unlock();
53→    }
54→
55→    /**
56→     * Establish or re-establish the underlying transport connection.
57→     */
58→    protected abstract void doConnect();
59→
60→    /**
61→     * Tear down the underlying transport connection.
62→     */
63→    protected abstract void doDisconnect();
64→
65→    /**
66→     * @return {@code true} if the current transport connection is still usable
67→     */
68→    protected abstract boolean isTransportValid();
69→
70→    /**
71→     * Performs a full reconnect cycle under exclusive lock. Subclasses should
72→     * call this when they detect a stale or broken transport.
73→     */
74→    protected void reconnect() {
75→        acquireExclusive();
76→        try {
77→            log.debug("Reconnecting metrics transport");
78→            doDisconnect();
79→            doConnect();
80→            lastConnectTimeMs = System.currentTimeMillis();
81→        } finally {
82→            releaseExclusive();
83→        }
84→    }
85→}
