217→        private void performActionsOnTasks() {
218→            tasksAndActionsLock.lock();
219→            try {
220→                for (final TaskAndAction taskAndAction : tasksAndActions()) {
221→                    final Action action = taskAndAction.action();
222→                    switch (action) {
223→                        case ADD:
224→                            addTask(taskAndAction.task());
225→                            break;
226→                        case REMOVE:
227→                            removeTask(taskAndAction.taskId(), taskAndAction.futureForRemove(), taskAndAction.suspendReason());
228→                            break;
229→                        default:
230→                            throw new IllegalStateException("Unknown action type " + action);
231→                    }
232→                }
233→            } finally {
234→                tasksAndActionsLock.unlock();
235→            }
236→        }
