238→        private void maybePerformTransportMaintenance() {
239→            if (metricsConnector != null) {
240→                final long nowMs = time.milliseconds();
241→                if (nowMs - lastTransportMaintenanceMs >= TRANSPORT_MAINTENANCE_INTERVAL_MS) {
242→                    lastTransportMaintenanceMs = nowMs;
243→                    try {
244→                        metricsConnector.performMaintenance();
245→                    } catch (final Exception e) {
246→                        log.warn("Metrics transport maintenance failed", e);
247→                    }
248→                }
249→            }
250→        }
