270→        private void restoreTasks(final long now) {
271→            try {
272→                final long restored = changelogReader.restore(updatingTasks);
273→                updaterMetrics.restoreSensor.record(restored, now);
274→            } catch (final TaskCorruptedException taskCorruptedException) {
275→                handleTaskCorruptedException(taskCorruptedException);
276→            } catch (final StreamsException streamsException) {
277→                handleStreamsException(streamsException);
278→            }
279→            final Set<TopicPartition> completedChangelogs = changelogReader.completedChangelogs();
280→            final List<Task> activeTasks = updatingTasks.values().stream().filter(Task::isActive).collect(Collectors.toList());
281→            for (final Task task : activeTasks) {
