286→        private void maybeGetClientInstanceIds() {
287→            if (fetchDeadlineClientInstanceId != -1) {
288→                if (!clientInstanceIdFuture.isDone()) {
289→                    if (fetchDeadlineClientInstanceId >= time.milliseconds()) {
290→                        try {
291→                            // if the state-updated thread has active work:
292→                            //    we pass in a timeout of zero into each `clientInstanceId()` call
293→                            //    to just trigger the "get instance id" background RPC;
294→                            //    we don't want to block the state updater thread that can do useful work in the meantime
295→                            // otherwise, we pass in 100ms to avoid busy waiting
296→                            clientInstanceIdFuture.complete(
297→                                restoreConsumer.clientInstanceId(
298→                                    allWorkDone() ? Duration.ofMillis(100L) : Duration.ZERO
299→                                )
300→                            );
301→                            fetchDeadlineClientInstanceId = -1L;
302→                        } catch (final IllegalStateException disabledError) {
303→                            // if telemetry is disabled on a client, we swallow the error,
304→                            // to allow returning a partial result for all other clients
305→                            clientInstanceIdFuture.complete(null);
306→                            fetchDeadlineClientInstanceId = -1L;
307→                        } catch (final TimeoutException swallow) {
308→                            // swallow
309→                        } catch (final Exception error) {
310→                            clientInstanceIdFuture.completeExceptionally(error);
311→                            fetchDeadlineClientInstanceId = -1L;
312→                        }
313→                    } else {
314→                        clientInstanceIdFuture.completeExceptionally(
315→                            new TimeoutException("Could not retrieve restore consumer client instance id.")
316→                        );
317→                        fetchDeadlineClientInstanceId = -1L;
318→                    }
319→                }
320→            }
321→        }
