323→        private KafkaFutureImpl<Uuid> restoreConsumerInstanceId(final Duration timeout) {
324→            boolean setDeadline = false;
325→
326→            if (clientInstanceIdFuture.isDone()) {
327→                if (clientInstanceIdFuture.isCompletedExceptionally()) {
328→                    clientInstanceIdFuture = new KafkaFutureImpl<>();
329→                    setDeadline = true;
330→                }
331→            } else {
332→                setDeadline = true;
333→            }
334→
335→            if (setDeadline) {
336→                fetchDeadlineClientInstanceId = time.milliseconds() + timeout.toMillis();
337→                tasksAndActionsLock.lock();
338→                try {
339→                    tasksAndActionsCondition.signalAll();
340→                } finally {
341→                    tasksAndActionsLock.unlock();
342→                }
343→            }
344→
345→            return clientInstanceIdFuture;
346→        }
