349→        private void handleRuntimeException(final RuntimeException runtimeException) {
350→            log.error("An unexpected error occurred within the state updater thread: {}", String.valueOf(runtimeException));
351→            addToExceptionsAndFailedTasksThenClearUpdatingAndPausedTasks(runtimeException);
352→            isRunning.set(false);
353→        }
