355→        private void handleTaskCorruptedException(final TaskCorruptedException taskCorruptedException) {
356→            log.info("Encountered task corrupted exception: ", taskCorruptedException);
357→            final Set<TaskId> corruptedTaskIds = taskCorruptedException.corruptedTasks();
358→            final Set<Task> corruptedTasks = new HashSet<>();
359→            final Set<TopicPartition> changelogsOfCorruptedTasks = new HashSet<>();
360→            for (final TaskId taskId : corruptedTaskIds) {
361→                final Task corruptedTask = updatingTasks.get(taskId);
362→                if (corruptedTask == null) {
363→                    throw new IllegalStateException("Task " + taskId + " is corrupted but is not updating. " + BUG_ERROR_MESSAGE);
364→                }
365→                corruptedTasks.add(corruptedTask);
366→                removeCheckpointForCorruptedTask(corruptedTask);
367→                changelogsOfCorruptedTasks.addAll(corruptedTask.changelogPartitions());
368→            }
369→            changelogReader.unregister(changelogsOfCorruptedTasks);
370→            corruptedTasks.forEach(
371→                task -> addToExceptionsAndFailedTasksThenRemoveFromUpdatingTasks(new ExceptionAndTask(taskCorruptedException, task))
372→            );
373→        }
374→
375→        // TODO: we can let the exception encode the actual corrupted changelog partitions and only
376→        //       mark those instead of marking all changelogs
377→        private void removeCheckpointForCorruptedTask(final Task task) {
378→            try {
379→                task.markChangelogAsCorrupted(task.changelogPartitions());
380→
381→                // we need to enforce a checkpoint that removes the corrupted partitions
382→                measureCheckpointLatency(() -> task.maybeCheckpoint(true));
383→            } catch (final StreamsException swallow) {
384→                log.warn("Checkpoint failed for corrupted task {}", task.id(), swallow);
385→            }
386→        }
387→
388→        private void handleStreamsException(final StreamsException streamsException) {
389→            log.info("Encountered streams exception: ", streamsException);
390→            if (streamsException.taskId().isPresent()) {
391→                handleStreamsExceptionWithTask(streamsException, streamsException.taskId().get());
392→            } else {
393→                handleStreamsExceptionWithoutTask(streamsException);
394→            }
395→        }
396→
397→        private void handleStreamsExceptionWithTask(final StreamsException streamsException, final TaskId failedTaskId) {
398→            if (updatingTasks.containsKey(failedTaskId)) {
399→                addToExceptionsAndFailedTasksThenRemoveFromUpdatingTasks(
400→                    new ExceptionAndTask(streamsException, updatingTasks.get(failedTaskId))
401→                );
402→            } else if (pausedTasks.containsKey(failedTaskId)) {
403→                addToExceptionsAndFailedTasksThenRemoveFromPausedTasks(
404→                    new ExceptionAndTask(streamsException, pausedTasks.get(failedTaskId))
