497→        private void addTask(final Task task) {
498→            final TaskId taskId = task.id();
499→
500→            Task existingTask = pausedTasks.get(taskId);
501→            if (existingTask != null) {
502→                throw new IllegalStateException(
503→                    (existingTask.isActive() ? "Active" : "Standby") + " task " + taskId + " already exist in paused tasks, " +
504→                        "should not try to add another " + (task.isActive() ? "active" : "standby") + " task with the same id. "
505→                        + BUG_ERROR_MESSAGE);
506→            }
507→            existingTask = updatingTasks.get(taskId);
508→            if (existingTask != null) {
509→                throw new IllegalStateException(
510→                    (existingTask.isActive() ? "Active" : "Standby") + " task " + taskId + " already exist in updating tasks, " +
511→                        "should not try to add another " + (task.isActive() ? "active" : "standby") + " task with the same id. "
512→                        + BUG_ERROR_MESSAGE);
513→            }
514→
515→            if (isStateless(task)) {
516→                addToRestoredTasks((StreamTask) task);
517→                log.info("Stateless active task " + taskId + " was added to the restored tasks of the state updater");
518→            } else if (topologyMetadata.isPaused(taskId.topologyName())) {
519→                pausedTasks.put(taskId, task);
520→                changelogReader.register(task.changelogPartitions(), task.stateManager());
521→                log.debug((task.isActive() ? "Active" : "Standby")
522→                    + " task " + taskId + " was directly added to the paused tasks.");
523→            } else {
524→                updatingTasks.put(taskId, task);
525→                changelogReader.register(task.changelogPartitions(), task.stateManager());
526→                if (task.isActive()) {
527→                    log.info("Stateful active task " + taskId + " was added to the state updater");
528→                    changelogReader.enforceRestoreActive();
529→                } else {
530→                    log.info("Standby task " + taskId + " was added to the state updater");
531→                    if (updatingTasks.size() == 1) {
532→                        changelogReader.transitToUpdateStandby();
533→                    }
534→                }
535→            }
536→        }
