721→            if (elapsedMsSinceLastCommit > commitIntervalMs) {
722→                if (log.isDebugEnabled()) {
723→                    log.debug("Checkpointing state of all restoring tasks since {}ms has elapsed (commit interval is {}ms)",
724→                        elapsedMsSinceLastCommit, commitIntervalMs);
725→                }
