956→    public Set<StreamTask> drainRestoredActiveTasks(final Duration timeout) {
957→        final long timeoutMs = timeout.toMillis();
958→        final long startTime = time.milliseconds();
959→        final long deadline = startTime + timeoutMs;
960→        long now = startTime;
961→        final Set<StreamTask> result = new HashSet<>();
962→        try {
963→            while (now <= deadline && result.isEmpty()) {
964→                restoredActiveTasksLock.lock();
965→                try {
966→                    while (restoredActiveTasks.isEmpty() && now <= deadline) {
967→                        // We can ignore whether the deadline expired during await, as the while loop condition will
968→                        // check again for deadline expiration.
969→                        @SuppressWarnings("UnusedLocalVariable")
970→                        final boolean ignored = restoredActiveTasksCondition.await(deadline - now, TimeUnit.MILLISECONDS);
971→                        now = time.milliseconds();
972→                    }
973→                    result.addAll(restoredActiveTasks);
974→                    restoredActiveTasks.clear();
975→                } finally {
976→                    restoredActiveTasksLock.unlock();
977→                }
978→                now = time.milliseconds();
979→            }
980→            return result;
981→        } catch (final InterruptedException ignored) {
982→        }
983→        return result;
984→    }
