1089→                        } catch (final InterruptedException e) {
1090→                            interrupted = true;
1091→                        }
1092→                    } else {
1093→                        log.debug("Cannot transit to {} within {}ms", targetState, timeoutMs);
1094→                        return false;
1095→                    }
1096→                    elapsedMs = time.milliseconds() - begin;
1097→                }
1098→                return true;
1099→            } finally {
1100→                // Make sure to restore the interruption status before returning.
1101→                // We do not always own the current thread that executes this method, i.e., we do not know the
1102→                // interruption policy of the thread. The least we can do is restore the interruption status before
1103→                // the current thread exits this method.
1104→                if (interrupted) {
